ALGORITHM UnsafeCounter
INPUT: None (shared global count)
OUTPUT: Final count value

BEGIN
 // This algorithm shows WHY thread safety is needed
 // count++ is actually 3 operations: READ, INCREMENT, WRITE

 PROCEDURE increment()
 temp = count // Step 1: READ current value
 temp = temp + 1 // Step 2: INCREMENT
 count = temp // Step 3: WRITE back
 END PROCEDURE

 // When two threads run concurrently:
 // Thread 1: READ count(0) -> temp=0
 // Thread 2: READ count(0) -> temp=0 (race!)
 // Thread 1: INCREMENT -> temp=1
 // Thread 2: INCREMENT -> temp=1
 // Thread 1: WRITE count=1
 // Thread 2: WRITE count=1
 // Result: count=1 instead of expected 2!
END

ALGORITHM SafeCounterWithMutex
INPUT: None (shared global count and mutex)
OUTPUT: Final count value

BEGIN
 DECLARE mutex lock
 DECLARE int count = 0

 PROCEDURE safe_increment()
 LOCK(lock) // Acquire exclusive access
 count = count + 1
 UNLOCK(lock) // Release lock
 END PROCEDURE

 // Only one thread can execute count++ at a time
 // Other threads wait at LOCK until unlock occurs
END

#include <stdio.h>
#include <pthread.h>
#include <stdlib.h>

// Shared counter structure
typedef struct {
 int count;
 pthread_mutex_t lock; // Mutex for synchronization
} Counter;

// Initialize counter with mutex
void counter_init(Counter *c) {
 c->count = 0;
 pthread_mutex_init(&c->lock, NULL); // Initialize mutex
}

// Thread-safe increment
void counter_increment(Counter *c) {
 pthread_mutex_lock(&c->lock); // LOCK - acquire exclusive access
 c->count++;
 pthread_mutex_unlock(&c->lock); // UNLOCK - release for others
}

// Thread-safe get value
int counter_get(Counter *c) {
 int value;
 pthread_mutex_lock(&c->lock);
 value = c->count;
 pthread_mutex_unlock(&c->lock);
 return value;
}

// Cleanup
void counter_destroy(Counter *c) {
 pthread_mutex_destroy(&c->lock);
}

// Thread function - each thread increments counter
void* thread_increment(void* arg) {
 Counter* c = (Counter*)arg;
 int increments = 10000;

 for (int i = 0; i < increments; i++) {
 counter_increment(c);
 }

 return NULL;
}

int main() {
 const int NUM_THREADS = 10;
 const int EXPECTED = NUM_THREADS * 10000;

 Counter shared_counter;
 counter_init(&shared_counter);

 pthread_t threads[NUM_THREADS];

 // Create threads
 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_create(&threads[i], NULL, thread_increment, &shared_counter);
 }

 // Wait for all threads
 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_join(threads[i], NULL);
 }

 int result = counter_get(&shared_counter);

 printf("Expected: %d\n", EXPECTED);
 printf("Got: %d\n", result);
 printf("Status: %s\n", result == EXPECTED ? "THREAD-SAFE!" : "RACE CONDITION!");

 counter_destroy(&shared_counter);

 return 0;
}

/* COMPILATION: gcc -pthread -o thread_safe thread_safe.c
 * 
 * KEY CONCEPTS DEMONSTRATED:
 * 1. pthread_mutex_lock() - enters critical section (only one thread allowed)
 * 2. pthread_mutex_unlock() - exits critical section
 * 3. Critical section = code that accesses shared data (count)
 * 4. Mutex ensures serialize access to critical section
 */

import java.util.concurrent.atomic.AtomicInteger;

/**
 * Demonstrates multiple approaches to thread-safe counters in Java
 */
public class ThreadSafeCounter {

 // APPROACH 1: Synchronized methods (intrinsic lock)
 static class SynchronizedCounter {
 private int count = 0;

 // synchronized keyword acquires object's intrinsic lock
 public synchronized void increment() {
 count++;
 }

 public synchronized int get() {
 return count;
 }
 }

 // APPROACH 2: Explicit lock (more flexible)
 static class LockCounter {
 private int count = 0;
 private final java.util.concurrent.locks.ReentrantLock lock 
 = new java.util.concurrent.locks.ReentrantLock();

 public void increment() {
 lock.lock();
 try {
 count++;
 } finally {
 lock.unlock(); // Always unlock in finally!
 }
 }

 public int get() {
 lock.lock();
 try {
 return count;
 } finally {
 lock.unlock();
 }
 }
 }

 // APPROACH 3: Atomic classes (lock-free, hardware-supported)
 static class AtomicCounter {
 // AtomicInteger uses CAS (Compare-And-Swap) operations
 private AtomicInteger count = new AtomicInteger(0);

 public void increment() {
 count.incrementAndGet(); // Thread-safe, lock-free
 }

 public int get() {
 return count.get();
 }
 }

 // Test runner
 public static void main(String[] args) throws InterruptedException {
 final int NUM_THREADS = 10;
 final int INCREMENTS = 10000;
 final int EXPECTED = NUM_THREADS * INCREMENTS;

 // Test synchronized counter
 SynchronizedCounter syncCounter = new SynchronizedCounter();
 runTest(syncCounter, NUM_THREADS, INCREMENTS, "Synchronized", EXPECTED);

 // Test lock counter
 LockCounter lockCounter = new LockCounter();
 runTest(lockCounter, NUM_THREADS, INCREMENTS, "ReentrantLock", EXPECTED);

 // Test atomic counter
 AtomicCounter atomicCounter = new AtomicCounter();
 runTest(atomicCounter, NUM_THREADS, INCREMENTS, "AtomicInteger", EXPECTED);
 }

 private static void runTest(Runnable counter, int numThreads, 
 int increments, String name, int expected) 
 throws InterruptedException {
 Thread[] threads = new Thread[numThreads];

 for (int i = 0; i < numThreads; i++) {
 threads[i] = new Thread(() -> {
 for (int j = 0; j < increments; j++) {
 counter.run();
 }
 });
 }

 for (Thread t : threads) t.start();
 for (Thread t : threads) t.join();

 // Note: This is simplified - in real code, need getter
 System.out.println(name + ": Expected " + expected + ", Got [check with getter]");
 }
}

/*
 * KEY CONCEPTS:
 * 
 * 1. synchronized: Uses object's intrinsic monitor lock
 * - Automatically acquires/releases lock
 * - Simple but less flexible
 * 
 * 2. ReentrantLock: Explicit lock object
 * - try-finally pattern required
 * - Supports tryLock(), timed waiting
 * 
 * 3. AtomicInteger: Hardware-level CAS operations
 * - Lock-free (better performance under low contention)
 * - Built-in methods: incrementAndGet(), getAndSet(), etc.
 * 
 * CHOOSE WISELY:
 * - synchronized: Simple, general use
 * - Atomic*: Single variable, high performance needed
 * - ReentrantLock: Complex locking scenarios
 */
